import { useEffect, useLayoutEffect, useState } from 'react';

function TimingDemo() {
  const [count, setCount] = useState(0);

  console.log('1. Render phase');

  useLayoutEffect(() => {
    console.log('3. useLayoutEffect (before paint)');
    return () => console.log('3. useLayoutEffect cleanup');
  });

  useEffect(() => {
    console.log('5. useEffect (after paint)');
    return () => console.log('5. useEffect cleanup');
  });

  return (
    <button onClick={() => setCount(c => c + 1)}>Count: {count}</button>
  );
}

// Console output on first render:
// 1. Render phase
// 3. useLayoutEffect (before paint)
// [browser paints the button]
// 5. useEffect (after paint)
//
// Console output on click (re-render):
// 1. Render phase
// 3. useLayoutEffect cleanup
// 3. useLayoutEffect (before paint)
// [browser paints updated count]
// 5. useEffect cleanup
// 5. useEffect (after paint)

function UserCard({ userId }) {
  const [user, setUser] = useState(null);

  useEffect(() => {
    fetch(`/api/users/${userId}`)
      .then(r => r.json())
      .then(data => setUser(data));
  }, [userId]);

  // First render: user = null → shows loading state
  // Second render: user = { name, ... } → shows user data
  if (!user) return <p>Loading...</p>;
  return <h1>{user.name}</h1>;
}

// Flickering tooltip — effect runs after paint, user sees wrong position briefly
function Tooltip({ anchor }) {
  const ref = useRef(null);
  const [pos, setPos] = useState({ top: 0, left: 0 });

  useEffect(() => {
    const rect = anchor.getBoundingClientRect();
    setPos({ top: rect.bottom + 4, left: rect.left }); // triggers re-render
  }, [anchor]);

  return <div ref={ref} style={pos}>...</div>; // first paint: pos = {0,0}
}

// Fix: useLayoutEffect — runs before paint, no flicker
function Tooltip({ anchor }) {
  const ref = useRef(null);
  const [pos, setPos] = useState({ top: 0, left: 0 });

  useLayoutEffect(() => {
    const rect = anchor.getBoundingClientRect();
    setPos({ top: rect.bottom + 4, left: rect.left });
  }, [anchor]);

  return <div ref={ref} style={pos}>...</div>; // paint after position is set
}

// React 18: both setState calls in effects are batched
useEffect(() => {
  setA(1); // ─┐ React batches these together
  setB(2); // ─┘ Only one re-render is triggered
});

// In React 17 and below, setState inside an effect
// from two different effects could trigger two separate renders.
// React 18 automatic batching eliminates this overhead.

// Development with StrictMode:
// [mount]  → render → paint → useEffect (first invocation)
// [unmount] → useEffect cleanup
// [remount] → render → paint → useEffect (second invocation)

// Production:
// [mount]  → render → paint → useEffect (single invocation)

// If dev and prod differ, the effect has side effects that don't clean up.

// Timeline for a single state-update render:
//
//  [frame N boundary]
//    React render phase  (< 1ms for small components)
//    React commit phase  (DOM mutations)
//    useLayoutEffect     (synchronous, still within the frame)
//    Browser layout + paint -> screen update
//  [frame N complete]
//
//  [frame N+1 or later -- browser idle]
//    useEffect callbacks fire (passive, via MessageChannel)
//
// Your useEffect code does NOT have to fit inside 16ms.
// A slow effect delays the NEXT render, not the current paint.

function Component() {
  useEffect(() => { console.log('A'); });
  useEffect(() => { console.log('B'); });
  useEffect(() => { console.log('C'); });
  return null;
}

// Console output after paint (always in order):
// A
// B
// C

// Cleanups on re-render also fire in order:
// A cleanup -> B cleanup -> C cleanup -> A -> B -> C

// React may start many renders but only commit some
//
// Render attempt 1 (interrupted by higher-priority update) -> no effect
// Render attempt 2 (interrupted by higher-priority update) -> no effect
// Render attempt 3 (committed) -> effect runs after paint

// The effect fires exactly once for the committed render.
// This is why effects must be idempotent -- React guarantees
// each committed render triggers effects once, in order.

useEffect(() => {
  performance.mark('effect-start');

  const result = expensiveComputation();
  setResult(result);

  performance.mark('effect-end');
  performance.measure('effect-duration', 'effect-start', 'effect-end');

  const [measure] = performance.getEntriesByName('effect-duration');
  console.log(`Effect took ${measure.duration.toFixed(2)}ms`);
}, [dep]);

// In browser DevTools Performance tab:
// The 'effect-duration' measure appears after the 'Paint' event.

function Analytics({ page }) {
  useEffect(() => {
    // Runs only in the browser, after hydration
    trackPageView(page);
  }, [page]);
  return null;
}

// During SSR:
// -> Component renders to HTML string
// -> useEffect callback is NOT called
// -> No browser API is accessed server-side

// After hydration on client:
// -> Component mounts -> useEffect fires -> trackPageView runs

// To profile effects:
// 1. Open React DevTools in browser
// 2. Click the Profiler tab
// 3. Click 'Start profiling'
// 4. Interact with your app
// 5. Click 'Stop profiling'
// 6. Click any flamegraph bar to see that render's effects

// In the timeline, effects appear after the 'Passive effects'
// label -- confirming they ran after paint.

function App() {
  useEffect(() => {
    // Runs once after the first paint
    initAnalytics();        // set up tracking
    registerServiceWorker(); // background caching
    prefetchNextPage();     // anticipatory data load
  }, []); // empty array = mount only

  return <Router />;
}

// These operations start AFTER the user sees the initial UI.
// The first paint is never held up waiting for them.

// ✗ Race condition — no cleanup, old fetch can win
function UserProfile({ userId }) {
  const [user, setUser] = useState(null);

  useEffect(() => {
    fetch(`/api/users/${userId}`)
      .then(r => r.json())
      .then(setUser); // could arrive late, overwrite newer data
  }, [userId]);

  return user ? <h1>{user.name}</h1> : <p>Loading...</p>;
}

// Scenario:
// userId = 1 -> effect starts fetch for user 1
// userId = 2 -> effect starts fetch for user 2 (no cleanup)
// user 1 fetch resolves late -> setUser(user1) overwrites user2 data

// ✓ No race condition — AbortController cleanup
function UserProfile({ userId }) {
  const [user, setUser] = useState(null);

  useEffect(() => {
    const controller = new AbortController();
    fetch(`/api/users/${userId}`, { signal: controller.signal })
      .then(r => r.json())
      .then(setUser)
      .catch(err => {
        if (err.name !== 'AbortError') setUser(null);
      });
    return () => controller.abort(); // cancel on userId change
  }, [userId]);

  return user ? <h1>{user.name}</h1> : <p>Loading...</p>;
}
